def lucide_icon(name: str, *, css_class: str = "", size: str = "") -> str:
    paths = LUCIDE.get(name, LUCIDE.get("search", ""))
    cls = "lucide-icon"
    if css_class:
        cls += f" {css_class}"
    size_attr = f' width="{size}" height="{size}"' if size else ""
    return (
        f'<svg class="{cls}" viewBox="0 0 24 24" fill="none" stroke="currentColor" '
        f'stroke-width="2" stroke-linecap="round" stroke-linejoin="round" '
        f'aria-hidden="true"{size_attr}>{paths}</svg>'
    )
